export const toFloat = (n: number) => +n.toFixed(2);

export const clearSelection = () => {
    const selection = window.getSelection();
    if (selection) {
        if (selection.empty) {
            // Chrome
            selection.empty();
        } else if (selection.removeAllRanges) {
            // Firefox
            selection.removeAllRanges();
        }
    }
};
